function Tarjeta({ id, titulo, img, descripcion,precio } , setCarrito, carrito, elemento) {

  const agregarAlCarrito = (e) => {
    setCarrito({ ...carrito, elemento})
    console.log(carrito)
  }

  return (
    <div className="tarjeta" id={id}>
      <img src={img} alt={titulo} />
      <div className="tarjeta-cont">
        <div className="texto-tarjeta">
          <h3>{titulo}</h3>
          <span>{precio}</span>
          <p>{descripcion}</p>
        </div>
        <div className="button-cont">
          <button
            onClick={() => agregarAlCarrito(carrito, props)}>
            <img
              id={id}
              src="/add-carrito.svg"
              alt="Carrito"
            />
          </button>
        </div>
      </div>
    </div>
  );
};

export default Tarjeta;
